//! Embedding model and response types for the Node.js bindings.

use std::sync::Arc;

use napi::bindgen_prelude::*;
use napi_derive::napi;

use blazen_llm::traits::EmbeddingModel;

#[cfg(feature = "fastembed")]
use crate::error::to_napi_error;
use crate::error::{blazen_error_to_napi, llm_error_to_napi};
use crate::generated::{JsProviderOptions, JsRequestTiming, JsTokenUsage};

// ---------------------------------------------------------------------------
// FastEmbed options (manual mirror — not auto-generated by build.rs)
// ---------------------------------------------------------------------------

/// Options for creating a local fastembed embedding model.
///
/// All fields are optional; defaults produce a working model using
/// `BAAI/bge-small-en-v1.5` on CPU with fastembed's built-in cache.
#[cfg(feature = "fastembed")]
#[napi(object)]
pub struct JsFastEmbedOptions {
    /// Fastembed model variant name (e.g. `"BGESmallENV15"`).
    pub model_name: Option<String>,
    /// Model cache directory. When absent, fastembed uses its built-in cache.
    pub cache_dir: Option<String>,
    /// Maximum batch size for embedding. When absent, fastembed uses its
    /// default (256).
    #[napi(js_name = "maxBatchSize")]
    pub max_batch_size: Option<u32>,
    /// Whether to display download progress when fetching models.
    #[napi(js_name = "showDownloadProgress")]
    pub show_download_progress: Option<bool>,
}

#[cfg(feature = "fastembed")]
impl From<JsFastEmbedOptions> for blazen_llm::FastEmbedOptions {
    fn from(val: JsFastEmbedOptions) -> Self {
        Self {
            model_name: val.model_name,
            cache_dir: val.cache_dir.map(std::path::PathBuf::from),
            max_batch_size: val.max_batch_size.map(|v| v as usize),
            show_download_progress: val.show_download_progress,
        }
    }
}

// ---------------------------------------------------------------------------
// EmbeddingResponse
// ---------------------------------------------------------------------------

/// The result of an embedding operation.
#[napi(object)]
pub struct JsEmbeddingResponse {
    /// The embedding vectors (one per input text).
    pub embeddings: Vec<Vec<f64>>,
    /// The model that produced these embeddings.
    pub model: String,
    /// Token usage statistics, if available.
    pub usage: Option<JsTokenUsage>,
    /// Estimated cost in USD, if available.
    pub cost: Option<f64>,
    /// Request timing breakdown, if available.
    pub timing: Option<JsRequestTiming>,
    /// Provider-specific metadata.
    pub metadata: serde_json::Value,
}

// ---------------------------------------------------------------------------
// EmbeddingModel wrapper
// ---------------------------------------------------------------------------

/// An embedding model that produces vector representations of text.
///
/// Use the static factory methods to create an instance for your provider:
///
/// ```javascript
/// const model = EmbeddingModel.openai({ apiKey: "sk-..." });
/// const response = await model.embed(["Hello", "World"]);
/// console.log(response.embeddings); // [[0.1, ...], [0.3, ...]]
/// ```
#[napi(js_name = "EmbeddingModel")]
pub struct JsEmbeddingModel {
    inner: Arc<dyn EmbeddingModel>,
}

impl JsEmbeddingModel {
    /// Access the inner embedding model (used by memory bindings).
    pub(crate) fn inner_arc(&self) -> Arc<dyn EmbeddingModel> {
        Arc::clone(&self.inner)
    }
}

#[napi]
#[allow(clippy::must_use_candidate, clippy::missing_errors_doc)]
impl JsEmbeddingModel {
    // -----------------------------------------------------------------
    // Provider factory methods
    // -----------------------------------------------------------------

    /// Create an `OpenAI` embedding model.
    ///
    /// Defaults to `text-embedding-3-small` (1536 dimensions).
    #[napi(factory)]
    pub fn openai(options: Option<JsProviderOptions>) -> Result<Self> {
        let api_key = blazen_llm::keys::resolve_api_key("openai", options.and_then(|o| o.api_key))
            .map_err(blazen_error_to_napi)?;
        Ok(Self {
            inner: Arc::new(blazen_llm::providers::openai::OpenAiEmbeddingModel::new(
                api_key,
            )),
        })
    }

    /// Create a Together AI embedding model.
    ///
    /// Defaults to `togethercomputer/m2-bert-80M-8k-retrieval` (768 dimensions).
    #[napi(factory)]
    pub fn together(options: Option<JsProviderOptions>) -> Result<Self> {
        let opts = options.map(Into::into).unwrap_or_default();
        Ok(Self {
            inner: Arc::new(
                blazen_llm::providers::openai_compat::OpenAiCompatEmbeddingModel::embedding_from_options("together", opts)
                    .map_err(blazen_error_to_napi)?,
            ),
        })
    }

    /// Create a Cohere embedding model.
    ///
    /// Defaults to `embed-v4.0` (1024 dimensions).
    #[napi(factory)]
    pub fn cohere(options: Option<JsProviderOptions>) -> Result<Self> {
        let opts = options.map(Into::into).unwrap_or_default();
        Ok(Self {
            inner: Arc::new(
                blazen_llm::providers::openai_compat::OpenAiCompatEmbeddingModel::embedding_from_options("cohere", opts)
                    .map_err(blazen_error_to_napi)?,
            ),
        })
    }

    /// Create a Fireworks AI embedding model.
    ///
    /// Defaults to `nomic-ai/nomic-embed-text-v1.5` (768 dimensions).
    #[napi(factory)]
    pub fn fireworks(options: Option<JsProviderOptions>) -> Result<Self> {
        let opts = options.map(Into::into).unwrap_or_default();
        Ok(Self {
            inner: Arc::new(
                blazen_llm::providers::openai_compat::OpenAiCompatEmbeddingModel::embedding_from_options("fireworks", opts)
                    .map_err(blazen_error_to_napi)?,
            ),
        })
    }

    // -----------------------------------------------------------------
    // Getters
    // -----------------------------------------------------------------

    /// The model identifier.
    #[napi(js_name = "modelId", getter)]
    pub fn model_id(&self) -> String {
        self.inner.model_id().to_owned()
    }

    /// The dimensionality of the embedding vectors produced by this model.
    #[napi(getter)]
    pub fn dimensions(&self) -> u32 {
        #[allow(clippy::cast_possible_truncation)]
        {
            self.inner.dimensions() as u32
        }
    }

    // -----------------------------------------------------------------
    // Embed
    // -----------------------------------------------------------------

    /// Embed one or more texts, returning one vector per input text.
    #[napi]
    pub async fn embed(&self, texts: Vec<String>) -> Result<JsEmbeddingResponse> {
        let response = self.inner.embed(&texts).await.map_err(llm_error_to_napi)?;

        Ok(JsEmbeddingResponse {
            // napi does not support Vec<Vec<f32>>; convert to f64 for JS.
            embeddings: response
                .embeddings
                .into_iter()
                .map(|v| v.into_iter().map(f64::from).collect())
                .collect(),
            model: response.model,
            usage: response.usage.map(Into::into),
            cost: response.cost,
            timing: response.timing.map(Into::into),
            metadata: response.metadata,
        })
    }
}

// ---------------------------------------------------------------------------
// Feature-gated fastembed factory (separate impl block required by napi-derive)
// ---------------------------------------------------------------------------

#[cfg(feature = "fastembed")]
#[napi]
#[allow(clippy::must_use_candidate, clippy::missing_errors_doc)]
impl JsEmbeddingModel {
    /// Create a local fastembed embedding model (ONNX Runtime, no API key).
    ///
    /// Defaults to `BAAI/bge-small-en-v1.5` (384 dimensions).
    ///
    /// ```javascript
    /// const model = EmbeddingModel.fastembed();
    /// const response = await model.embed(["Hello", "World"]);
    /// ```
    #[napi(factory)]
    pub fn fastembed(options: Option<JsFastEmbedOptions>) -> Result<Self> {
        let opts = options.map(Into::into).unwrap_or_default();
        let model = blazen_llm::FastEmbedModel::from_options(opts).map_err(to_napi_error)?;
        Ok(Self {
            inner: Arc::new(model),
        })
    }
}
